/** Etichetta tradotta per un weather attribute key, con fallback al label backend. */
export function attrLabel(key: string, fallback?: string): string {
  const tk = `weather.attr.${key}`;
  const v = t(tk);
  return v === tk ? (fallback || key) : v;
}
